'use strict';

/**
 * 生成 OpenCode TUI plugin。插件在普通 embedded TUI 内运行，通过 Walker
 * 的 loopback API 收取飞书 prompt，再使用当前 TUI 的本地 SDK 执行。
 */
function getPluginSource(walkerPort, token, heartbeatIntervalMs) {
  const port = Number(walkerPort) || 8787;
  const safeToken = typeof token === 'string' ? token : '';
  const safeHeartbeatMs = Number(heartbeatIntervalMs) > 0 ? Number(heartbeatIntervalMs) : 30000;
  return `// Walker TUI bridge version: 14
// Auto-generated by Walker. Do not edit; Walker may update this file on startup.

const REGISTER_URL = ${JSON.stringify('http://127.0.0.1:' + port + '/opencode/tui-bridge/register')};
const POLL_URL = ${JSON.stringify('http://127.0.0.1:' + port + '/opencode/tui-bridge/poll')};
const EVENTS_URL = ${JSON.stringify('http://127.0.0.1:' + port + '/opencode/tui-bridge/events')};
const DISPOSE_URL = ${JSON.stringify('http://127.0.0.1:' + port + '/opencode/tui-bridge/dispose')};
const WALKER_TOKEN = ${JSON.stringify(safeToken)};
const POLL_INTERVAL_MS = 500;
const HEARTBEAT_INTERVAL_MS = ${safeHeartbeatMs};

function createRuntimeId() {
  if (globalThis.crypto && typeof globalThis.crypto.randomUUID === 'function') {
    return globalThis.crypto.randomUUID();
  }
  return 'runtime-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2);
}

async function post(url, body) {
  const headers = { 'Content-Type': 'application/json' };
  if (WALKER_TOKEN) headers.Authorization = 'Bearer ' + WALKER_TOKEN;
  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify(body),
  });
  const payload = await response.json().catch(() => null);
  if (!response.ok || !payload || payload.ok !== true) {
    const message = payload && payload.error && payload.error.message;
    throw new Error(message || 'Walker TUI bridge request failed: HTTP ' + response.status);
  }
  return payload.data || {};
}

function currentSessionId(api) {
  const route = api.route.current;
  return route && route.name === 'session' && route.params ? route.params.sessionID : '';
}

function currentDirectory(api) {
  const directory = api.state && api.state.path && api.state.path.directory;
  if (directory) return directory;
  try {
    return typeof process !== 'undefined' && process.cwd ? process.cwd() : '';
  } catch (_) {
    return '';
  }
}

function eventProperties(event) {
  return event && (event.properties || (event.payload && event.payload.properties)) || {};
}

function pickPermissionRequest(properties) {
  return properties && (properties.permission || properties.request || properties.input || properties.data) || properties || {};
}

function errorMessage(value) {
  if (typeof value === 'string' && value) return value;
  if (!value || typeof value !== 'object') return value ? String(value) : 'OpenCode session error';
  if (typeof value.message === 'string' && value.message) return value.message;
  for (const nested of [value.data, value.error, value.cause]) {
    if (nested && nested !== value) {
      const message = errorMessage(nested);
      if (message && message !== 'OpenCode session error') return message;
    }
  }
  if (typeof value.name === 'string' && value.name) return value.name;
  try {
    const serialized = JSON.stringify(value);
    if (serialized && serialized !== '{}') return serialized;
  } catch (_) {}
  return 'OpenCode session error';
}

function stateMessages(api, sessionId) {
  const source = api.state && api.state.session && api.state.session.messages;
  if (typeof source === 'function') return source(sessionId) || [];
  return source && source[sessionId] || [];
}

function stateParts(api, messageId) {
  const source = api.state && api.state.part;
  if (typeof source === 'function') return source(messageId) || [];
  return source && source[messageId] || [];
}

function finalEvents(api, sessionId) {
  const messages = stateMessages(api, sessionId);
  const assistant = [...messages].reverse().find((message) => message && message.role === 'assistant');
  if (!assistant || !assistant.id) {
    console.warn('[walker-bridge] finalEvents: no assistant message found', { sessionId, messagesCount: messages.length, lastMessageRole: messages.length ? messages[messages.length - 1] && messages[messages.length - 1].role : 'none' });
    return { messageId: '', events: [] };
  }
  const events = [];
  for (const part of stateParts(api, assistant.id)) {
    const text = part && (part.text || part.content || part.value || '');
    if (part && part.type === 'text' && text) events.push({ type: 'text', data: { text } });
    if (part && part.type === 'reasoning' && text) events.push({ type: 'reasoning', data: { text } });
    if (part && (part.type === 'tool' || part.type === 'tool-use')) {
      events.push({
        type: 'tool_use',
        data: {
          name: part.tool || part.toolName || part.name || '',
          input: part.state && part.state.input || part.input || {},
          output: part.state && part.state.output || part.output || '',
          status: part.state && part.state.status || '',
        },
      });
    }
    if (part && (part.type === 'file' || part.type === 'patch')) {
      events.push({
        type: 'file_edited',
        data: {
          path: part.path || part.file || part.name || '',
          action: part.type === 'patch' ? 'patch' : (part.action || 'edit'),
          linesAdded: part.linesAdded,
          linesRemoved: part.linesRemoved,
        },
      });
    }
  }
  events.push({ type: 'done', data: { reason: 'idle' } });
  return { messageId: assistant.id, events };
}

function extractSessionId(result) {
  if (!result || typeof result !== 'object') return '';
  if (result.data && typeof result.data.id === 'string' && result.data.id) return result.data.id;
  if (typeof result.id === 'string' && result.id) return result.id;
  if (typeof result.sessionID === 'string' && result.sessionID) return result.sessionID;
  if (typeof result.sessionId === 'string' && result.sessionId) return result.sessionId;
  return '';
}

async function tui(api) {
  const runtimeId = createRuntimeId();
  const activeDeliveries = new Map();
  let activeQuestionDelivery = null;
  const sentAssistantIds = new Set();
  let stopped = false;
  let busy = false;
  let activeSessionId = currentSessionId(api);
  let lastRegisteredSessionId = '';
  let lastRegisteredAt = 0;

  let activeClear = null;
  const clearEventBuffer = [];

  async function register(sessionId, force, extra) {
    if (!force && sessionId === lastRegisteredSessionId && lastRegisteredAt) return;
    const body = {
      runtimeId,
      sessionId,
      cwd: currentDirectory(api),
      opencodeVersion: api.app && api.app.version || '',
      bridgeProtocolVersion: 5,
    };
    if (extra) Object.assign(body, extra);
    await post(REGISTER_URL, body);
    if (!extra || !extra.controlDeliveryId) {
      lastRegisteredSessionId = sessionId;
      lastRegisteredAt = Date.now();
    }
  }

  async function report(sessionId, deliveryId, events, error, control, deliveryState) {
    const body = { runtimeId, sessionId, deliveryId: deliveryId || undefined, events: events || [], error };
    if (control) body.control = control;
    if (deliveryState) body.deliveryState = deliveryState;
    return post(EVENTS_URL, body);
  }

  function startHeartbeat(sessionId, deliveryId) {
    const entry = activeDeliveries.get(sessionId);
    if (!entry || entry.heartbeatTimer) return;
    entry.heartbeatTimer = setInterval(async () => {
      try {
        await report(sessionId, deliveryId, [], null, null, 'heartbeat');
      } catch (_) {}
    }, HEARTBEAT_INTERVAL_MS);
    if (entry.heartbeatTimer.unref) entry.heartbeatTimer.unref();
  }

  function stopHeartbeat(sessionId) {
    const entry = activeDeliveries.get(sessionId);
    if (!entry || !entry.heartbeatTimer) return;
    clearInterval(entry.heartbeatTimer);
    entry.heartbeatTimer = null;
  }

  function questionReplyError(error, code, deliveryPhase, sdkInvoked, safeToRetry) {
    return {
      message: errorMessage(error) || 'question reply failed',
      code: code || error && error.code || 'QUESTION_REPLY_FAILED',
      deliveryPhase,
      sdkInvoked: Boolean(sdkInvoked),
      safeToRetry: Boolean(safeToRetry),
    };
  }

  function errorMessage(error) {
    if (!error) return '';
    if (typeof error === 'string') return error;
    if (typeof error.message === 'string') return error.message;
    if (error.message) return stringifyErrorValue(error.message);
    if (typeof error.error === 'string') return error.error;
    if (error.error) return stringifyErrorValue(error.error);
    if (error.body) return stringifyErrorValue(error.body);
    if (error.data) return stringifyErrorValue(error.data);
    return stringifyErrorValue(error);
  }

  function stringifyErrorValue(value) {
    try {
      return JSON.stringify(value);
    } catch (_) {
      return String(value);
    }
  }

  function validQuestionReply(delivery) {
    return typeof delivery.requestID === 'string' && delivery.requestID
      && Array.isArray(delivery.answers) && delivery.answers.length > 0
      && delivery.answers.every((answer) => Array.isArray(answer) && answer.length > 0
        && answer.every((value) => typeof value === 'string' && value));
  }

  function validPermissionReply(delivery) {
    return typeof delivery.permissionId === 'string' && delivery.permissionId
      && typeof delivery.response === 'string' && delivery.response;
  }

  function permissionResponseForSdk(response, remember) {
    if (response === 'deny' || response === 'reject') return 'reject';
    if (response === 'always') return 'always';
    if (remember) return 'always';
    return 'once';
  }

  function startQuestionHeartbeat() {
    const control = activeQuestionDelivery;
    if (!control || control.heartbeatTimer) return;
    control.heartbeatTimer = setInterval(async () => {
      try {
        await report(control.sessionId, control.deliveryId, [], null, null, 'heartbeat');
      } catch (_) {}
    }, HEARTBEAT_INTERVAL_MS);
    if (control.heartbeatTimer.unref) control.heartbeatTimer.unref();
  }

  function clearQuestionDelivery() {
    if (!activeQuestionDelivery) return;
    if (activeQuestionDelivery.heartbeatTimer) clearInterval(activeQuestionDelivery.heartbeatTimer);
    activeQuestionDelivery = null;
  }

  async function progressQuestionDelivery() {
    const control = activeQuestionDelivery;
    if (!control) return;
    if (control.state === 'awaitingAccepted') {
      try {
        const accepted = await report(control.sessionId, control.deliveryId, [], null, null, 'accepted');
        if (accepted && accepted.expired === true) {
          clearQuestionDelivery();
          return;
        }
      } catch (_) {
        return;
      }
      control.state = 'executingSdk';
      const questionClient = api.client && api.client.question;
      if (!questionClient || typeof questionClient.reply !== 'function') {
        control.finalError = questionReplyError(
          new Error('OpenCode SDK question.reply is unavailable'),
          'QUESTION_REPLY_UNSUPPORTED', 'queued', false, false,
        );
        control.state = 'finalizing';
        return progressQuestionDelivery();
      }
      control.sdkInvoked = true;
      startQuestionHeartbeat();
      try {
        const result = await questionClient.reply({ requestID: control.requestID, answers: control.answers });
        if (result && result.error) throw result.error;
        control.finalError = null;
      } catch (error) {
        control.finalError = questionReplyError(error, error && error.code || 'QUESTION_REPLY_SDK_FAILED', 'leased', true, false);
      }
      control.state = 'finalizing';
    }
    if (control.state === 'finalizing') {
      try {
        await report(control.sessionId, control.deliveryId, [], control.finalError, null, 'final');
        clearQuestionDelivery();
      } catch (_) {}
    }
  }

  async function executeQuestionDelivery(delivery) {
    if (activeQuestionDelivery) return;
    const control = {
      deliveryId: delivery.deliveryId,
      sessionId: delivery.sessionId,
      requestID: delivery.requestID,
      answers: delivery.answers,
      heartbeatTimer: null,
      state: 'awaitingAccepted',
      sdkInvoked: false,
      finalError: null,
    };
    activeQuestionDelivery = control;
    if (!validQuestionReply(delivery)) {
      control.state = 'finalizing';
      control.finalError = questionReplyError(
        new Error('question_reply requires a requestID and non-empty string answers'),
        'QUESTION_REPLY_INVALID_PAYLOAD', 'queued', false, false,
      );
    }
    await progressQuestionDelivery();
  }

  async function executePermissionDelivery(delivery) {
    const sessionId = delivery.sessionId;
    try {
      const accepted = await report(sessionId, delivery.deliveryId, [], null, null, 'accepted');
      if (accepted && accepted.expired === true) return;
    } catch (_) {
      return;
    }

    let sdkInvoked = false;
    let finalError = null;
    const entry = { heartbeatTimer: null };
    activeDeliveries.set(sessionId, entry);
    try {
      if (!validPermissionReply(delivery)) {
        finalError = questionReplyError(
          new Error('permission_reply requires a permissionId and response'),
          'PERMISSION_REPLY_INVALID_PAYLOAD', 'queued', false, false,
        );
      } else {
        const permissionClient = api.client && api.client.permission;
        const sdkResponse = permissionResponseForSdk(delivery.response, delivery.remember);
        if (permissionClient && typeof permissionClient.reply === 'function') {
          sdkInvoked = true;
          startHeartbeat(sessionId, delivery.deliveryId);
          const result = await permissionClient.reply({
            requestID: delivery.permissionId,
            reply: sdkResponse,
            directory: currentDirectory(api),
          });
          if (result && result.error) throw result.error;
        } else {
          finalError = questionReplyError(
            new Error('OpenCode SDK permission reply is unavailable'),
            'PERMISSION_REPLY_UNSUPPORTED', 'queued', false, false,
          );
        }
      }
    } catch (error) {
      finalError = questionReplyError(error, error && error.code || 'PERMISSION_REPLY_SDK_FAILED', sdkInvoked ? 'leased' : 'queued', sdkInvoked, false);
    } finally {
      stopHeartbeat(sessionId);
      activeDeliveries.delete(sessionId);
    }

    await report(sessionId, delivery.deliveryId, [], finalError, null, 'final').catch(() => {});
  }

  async function executeDelivery(delivery) {
    if (!delivery || !delivery.deliveryId) {
      console.warn('[walker-bridge] executeDelivery: empty delivery', { delivery });
      return;
    }
    console.warn('[walker-bridge] executeDelivery: received', { deliveryId: delivery.deliveryId, type: delivery.type, deliverySessionId: delivery.sessionId, activeSessionId, text: (delivery.text || '').slice(0, 50) });
    if (delivery.type === 'question_reply') {
      await executeQuestionDelivery(delivery);
      return;
    }
    if (delivery.type === 'permission_reply') {
      await executePermissionDelivery(delivery);
      return;
    }
    if (delivery.type === 'clear') {
      await executeClearDelivery(delivery);
      return;
    }
    const sessionId = activeSessionId;
    if (sessionId !== delivery.sessionId) {
      console.warn('[walker-bridge] executeDelivery: sessionId mismatch, skipping', { activeSessionId: sessionId, deliverySessionId: delivery.sessionId });
      return;
    }
    activeDeliveries.set(sessionId, { deliveryId: delivery.deliveryId, heartbeatTimer: null });
    console.warn('[walker-bridge] executeDelivery: activeDeliveries set', { sessionId, deliveryId: delivery.deliveryId });
    try {
      await report(sessionId, delivery.deliveryId, [], null, null, 'accepted');
      if (currentSessionId(api) !== sessionId) {
        api.route.navigate('session', { sessionID: sessionId });
      }
      const promptParams = {
        sessionID: sessionId,
        parts: [{ type: 'text', text: delivery.text || '' }],
      };
      if (delivery.model) {
        promptParams.model = delivery.model;
      }
      const result = await api.client.session.promptAsync(promptParams);
      if (result && result.error) throw new Error(errorMessage(result.error));
      startHeartbeat(sessionId, delivery.deliveryId);
    } catch (error) {
      stopHeartbeat(sessionId);
      activeDeliveries.delete(sessionId);
      await report(sessionId, delivery.deliveryId, [], { message: error.message || String(error) }, null, 'final').catch(() => {});
    }
  }

  async function executeClearDelivery(delivery) {
    const oldSessionId = delivery.sessionId;
    if (activeSessionId !== oldSessionId) return;

    activeClear = {
      deliveryId: delivery.deliveryId,
      oldSessionId,
      suppressSessionId: null,
      navigated: false,
      completed: false,
      failed: false,
    };

    let newSessionId = '';
    try {
      const createResult = await api.client.session.create({ title: delivery.title });
      newSessionId = extractSessionId(createResult);
      if (!newSessionId) throw new Error('OpenCode session create returned no session id');
      if (!activeClear || activeClear.deliveryId !== delivery.deliveryId) return;
      activeClear.suppressSessionId = newSessionId;
    } catch (error) {
      if (activeClear && activeClear.deliveryId === delivery.deliveryId) {
        activeClear.failed = true;
        await report(oldSessionId, delivery.deliveryId, [], { message: error.message || String(error) }).catch(() => {});
        activeClear = null;
        flushClearEventBuffer();
      }
      return;
    }

    try {
      api.route.navigate('session', { sessionID: newSessionId });
      activeClear.navigated = true;
    } catch (error) {
      if (activeClear && activeClear.deliveryId === delivery.deliveryId) {
        activeClear.failed = true;
        await report(oldSessionId, delivery.deliveryId, [], { message: error.message || String(error) }).catch(() => {});
        activeClear = null;
        flushClearEventBuffer();
      }
      return;
    }

    const controlBody = { runtimeId, sessionId: oldSessionId, deliveryId: delivery.deliveryId, control: { type: 'clear', newSessionId } };
    const registerBody = {
      runtimeId,
      sessionId: newSessionId,
      cwd: currentDirectory(api),
      opencodeVersion: api.app && api.app.version || '',
      bridgeProtocolVersion: 5,
      controlDeliveryId: delivery.deliveryId,
    };

    let controlOk = false;
    let registerOk = false;
    let controlError = null;
    let registerError = null;

    try {
      await post(EVENTS_URL, controlBody);
      controlOk = true;
    } catch (error) {
      controlError = error;
    }

    try {
      await post(REGISTER_URL, registerBody);
      registerOk = true;
    } catch (error) {
      registerError = error;
    }

    if (controlOk && registerOk) {
      activeClear.completed = true;
      activeSessionId = newSessionId;
      lastRegisteredSessionId = newSessionId;
      lastRegisteredAt = Date.now();
      activeClear = null;
      flushClearEventBuffer();
      return;
    }

    const failError = controlError || registerError;
    const failMessage = failError ? (failError.message || String(failError)) : 'clear associated reporting failed';
    if (activeClear && activeClear.deliveryId === delivery.deliveryId) {
      activeClear.failed = true;
      await report(oldSessionId, delivery.deliveryId, [], { message: failMessage }).catch(() => {});
      if (activeClear.navigated) {
        try {
          api.route.navigate('session', { sessionID: oldSessionId });
        } catch (rollbackError) {
          await report(oldSessionId, delivery.deliveryId, [], {
            message: failMessage + '；回滚失败：' + (rollbackError.message || String(rollbackError)) + '，请手工切回旧 session',
          }).catch(() => {});
        }
      }
      activeClear = null;
      flushClearEventBuffer();
    }
  }

  function flushClearEventBuffer() {
    if (activeClear) return;
    const buffered = clearEventBuffer.splice(0);
    for (const item of buffered) {
      if (item.type === 'session.created') {
        handleSessionCreated(item.event, true);
      } else if (item.type === 'tui.session.select') {
        handleTuiSessionSelect(item.event, true);
      }
    }
  }

  async function tick() {
    if (stopped || busy) return;
    if (!activeSessionId) activeSessionId = currentSessionId(api);
    const sessionId = activeSessionId;
    if (!sessionId) return;
    if (activeClear && activeClear.oldSessionId === sessionId) return;
    if (activeQuestionDelivery) {
      busy = true;
      try {
        await progressQuestionDelivery();
      } finally {
        busy = false;
      }
      return;
    }
    const status = api.state && api.state.session && api.state.session.status(sessionId);
    const statusType = status && status.type;
    busy = true;
    try {
      await register(sessionId, false);
      const parentActive = activeDeliveries.has(sessionId);
      const acceptedTypes = parentActive || (statusType && statusType !== 'idle')
        ? ['question_reply', 'permission_reply']
        : ['prompt', 'clear', 'question_reply', 'permission_reply'];
      const data = await post(POLL_URL, { runtimeId, sessionId, acceptedTypes });
      if (data.delivery) await executeDelivery(data.delivery);
    } catch (_) {
      lastRegisteredAt = 0;
    } finally {
      busy = false;
    }
  }

  async function selectSession(sessionId) {
    if (!sessionId) return;
    if (activeClear && activeClear.suppressSessionId === sessionId) return;
    if (sessionId !== activeSessionId) {
      activeSessionId = sessionId;
      lastRegisteredSessionId = '';
      lastRegisteredAt = 0;
    }
    await tick();
  }

  function handleSessionCreated(event, fromBuffer) {
    const properties = eventProperties(event);
    const info = properties.info || {};
    if (info.parentID || info.parentId) return;
    const sessionId = properties.sessionID || properties.sessionId || info.id;
    if (!sessionId) return;
    if (activeClear) {
      if (activeClear.suppressSessionId === sessionId) return;
      if (!fromBuffer) clearEventBuffer.push({ type: 'session.created', event });
      return;
    }
    return selectSession(sessionId);
  }

  function handleTuiSessionSelect(event, fromBuffer) {
    const properties = eventProperties(event);
    const sessionId = properties.sessionID || properties.sessionId;
    if (!sessionId) return;
    if (activeClear) {
      if (activeClear.suppressSessionId === sessionId) return;
      if (!fromBuffer) clearEventBuffer.push({ type: 'tui.session.select', event });
      return;
    }
    return selectSession(sessionId);
  }

  api.event.on('session.created', async (event) => {
    await handleSessionCreated(event);
  });

  api.event.on('tui.session.select', async (event) => {
    await handleTuiSessionSelect(event);
  });

  api.event.on('session.idle', async (event) => {
    const properties = eventProperties(event);
    const sessionId = properties.sessionID || properties.sessionId;
    if (!sessionId) {
      console.warn('[walker-bridge] session.idle ignored: no sessionId');
      return;
    }
    const result = finalEvents(api, sessionId);
    if (!result.messageId) {
      console.warn('[walker-bridge] session.idle finalEvents empty, skipping report', { sessionId });
      return;
    }
    if (sentAssistantIds.has(result.messageId)) {
      console.warn('[walker-bridge] session.idle assistant already sent', { sessionId, messageId: result.messageId, eventCount: result.events.length });
      return;
    }
    sentAssistantIds.add(result.messageId);
    const entry = activeDeliveries.get(sessionId);
    const deliveryId = entry ? entry.deliveryId : '';
    const deliveryState = entry ? 'final' : null;
    if (entry) {
      stopHeartbeat(sessionId);
      activeDeliveries.delete(sessionId);
    }
    console.warn('[walker-bridge] session.idle reporting final', { sessionId, deliveryId, hasActiveDelivery: Boolean(entry), messageId: result.messageId, eventCount: result.events.length, eventTypes: result.events.map((e) => e.type).join(',') });
    await report(sessionId, deliveryId, result.events, null, null, deliveryState).catch((err) => {
      console.warn('[walker-bridge] session.idle report failed', { sessionId, deliveryId, error: err && err.message });
    });
  });

  api.event.on('session.error', async (event) => {
    const properties = eventProperties(event);
    const sessionId = properties.sessionID || properties.sessionId || activeSessionId;
    if (!sessionId) return;
    const entry = activeDeliveries.get(sessionId);
    if (!entry) return;
    const deliveryId = entry.deliveryId;
    const deliveryState = 'final';
    stopHeartbeat(sessionId);
    activeDeliveries.delete(sessionId);
    const error = { message: errorMessage(properties.error) };
    await report(sessionId, deliveryId, [], error, null, deliveryState).catch(() => {});
  });

  function reportPermissionEvent(type, event) {
    const properties = eventProperties(event);
    const request = pickPermissionRequest(properties);
    const metadata = request.metadata || properties.metadata || {};
    const sessionId = properties.sessionID || properties.sessionId || request.sessionID || request.sessionId || activeSessionId;
    if (!sessionId) return Promise.resolve();
    if (type === 'permission_replied') {
      const permissionId = properties.permissionId || properties.id || request.permissionId || request.id || '';
      if (!permissionId) return Promise.resolve();
      return report(sessionId, '', [{ type, data: {
        permissionId,
        response: properties.response || properties.action || properties.decision || request.response || request.action || request.decision || '',
        sessionID: sessionId,
      } }], null, null, null).catch(() => {});
    }
    const permissionId = properties.id || properties.permissionId || request.id || request.permissionId || '';
    if (!permissionId) return Promise.resolve();
    const permissionType = properties.permission || request.permission || properties.type || request.type || '';
    const permissionPatterns = Array.isArray(properties.patterns) ? properties.patterns
      : (Array.isArray(request.patterns) ? request.patterns
        : (Array.isArray(metadata.patterns) ? metadata.patterns : []));
    const title = properties.title || request.title || permissionTitle(permissionType, permissionPatterns);
    return report(sessionId, '', [{ type: 'permission', data: {
      id: permissionId,
      type: permissionType,
      title: title,
      description: properties.description || request.description || '',
      metadata: {
        ...metadata,
        patterns: permissionPatterns.length ? permissionPatterns : undefined,
        pattern: metadata.pattern || request.pattern || properties.pattern || undefined,
      },
      sessionID: sessionId,
      messageID: properties.messageID || properties.messageId || request.messageID || request.messageId || '',
      callID: properties.callID || properties.callId || request.callID || request.callId || undefined,
    } }], null, null, null).catch(() => {});
  }

  function permissionTitle(permissionType, patterns) {
    if (!permissionType || typeof permissionType !== 'string') return '';
    const map = {
      external_directory: '访问外部目录',
      bash: '执行 bash 命令',
      edit: '编辑文件',
      write: '写入文件',
      webfetch: '访问网络',
    };
    const base = map[permissionType] || ('权限请求: ' + permissionType);
    const path = extractPermissionPath(patterns);
    return path ? (base + ' ' + path) : base;
  }

  function extractPermissionPath(patterns) {
    if (!Array.isArray(patterns) || patterns.length === 0) return '';
    const first = patterns[0];
    if (typeof first !== 'string' || !first) return '';
    return first.replace(/[/\\\\]*\\*+$/, '').replace(/[\\*]/g, '');
  }

  api.event.on('permission.asked', async (event) => {
    await reportPermissionEvent('permission', event);
  });

  api.event.on('permission.updated', async (event) => {
    await reportPermissionEvent('permission', event);
  });

  api.event.on('permission.replied', async (event) => {
    await reportPermissionEvent('permission_replied', event);
  });

  function reportQuestionEvent(type, event) {
    const properties = eventProperties(event);
    const request = properties.request || properties;
    const sessionID = properties.sessionID || properties.sessionId || request.sessionID || request.sessionId || activeSessionId;
    const requestID = request.requestID || request.id || properties.requestID || properties.id;
    if (!sessionID || !requestID) {
      console.error('Walker received an invalid native question event');
      return Promise.resolve();
    }
    if (type === 'question_asked') {
      if (!Array.isArray(request.questions) || request.questions.length === 0) {
        console.error('Walker received native question.asked without questions');
        return Promise.resolve();
      }
      const data = { requestID, sessionID, questions: request.questions };
      if (request.tool || properties.tool) data.tool = request.tool || properties.tool;
      return report(sessionID, '', [{ type, data }], null, null, null).catch(() => {});
    }
    if (type === 'question_replied') {
      if (!Array.isArray(request.answers)) {
        console.error('Walker received native question.replied without answers');
        return Promise.resolve();
      }
      return report(sessionID, '', [{ type, data: { requestID, sessionID, answers: request.answers } }], null, null, null).catch(() => {});
    }
    return report(sessionID, '', [{ type, data: { requestID, sessionID } }], null, null, null).catch(() => {});
  }

  api.event.on('question.asked', async (event) => {
    await reportQuestionEvent('question_asked', event);
  });

  api.event.on('question.replied', async (event) => {
    await reportQuestionEvent('question_replied', event);
  });

  api.event.on('question.rejected', async (event) => {
    await reportQuestionEvent('question_rejected', event);
  });

  api.event.on('todo.updated', async (event) => {
    const properties = eventProperties(event);
    const sessionId = properties.sessionID || properties.sessionId || activeSessionId;
    if (!sessionId) return;
    await report(sessionId, '', [{ type: 'todo', data: { todos: properties.todos || [] } }], null, null, null).catch(() => {});
  });

  api.event.on('session.compacted', async (event) => {
    const properties = eventProperties(event);
    const sessionId = properties.sessionID || properties.sessionId || activeSessionId;
    if (!sessionId) return;
    await report(sessionId, '', [{ type: 'compacted', data: { sessionID: sessionId } }], null, null, null).catch(() => {});
  });

  api.event.on('file.edited', async (event) => {
    const properties = eventProperties(event);
    const sessionId = properties.sessionID || properties.sessionId || activeSessionId;
    if (!sessionId) return;
    await report(sessionId, '', [{ type: 'file_edited', data: {
      path: properties.path || '',
      action: properties.action || 'edit',
      linesAdded: properties.linesAdded,
      linesRemoved: properties.linesRemoved,
    } }], null, null, null).catch(() => {});
  });

  api.event.on('command.executed', async (event) => {
    const properties = eventProperties(event);
    const sessionId = properties.sessionID || properties.sessionId || activeSessionId;
    if (!sessionId) return;
    await report(sessionId, '', [{ type: 'command_executed', data: {
      command: properties.command || '',
      exitCode: properties.exitCode !== undefined ? properties.exitCode : -1,
    } }], null, null, null).catch(() => {});
  });

  api.event.on('message.part.updated', async (event) => {
    const properties = eventProperties(event);
    const sessionId = properties.sessionID || properties.sessionId || activeSessionId;
    if (!sessionId) return;
    if (activeDeliveries.has(sessionId)) return;
    const part = properties.part || {};
    if (part.type === 'file' || part.type === 'patch') {
      await report(sessionId, '', [{ type: 'file_edited', data: {
        path: part.path || part.file || part.name || '',
        action: part.type === 'patch' ? 'patch' : (part.action || 'edit'),
        linesAdded: part.linesAdded,
        linesRemoved: part.linesRemoved,
      } }], null, null, null).catch(() => {});
    }
  });

  const timer = setInterval(tick, POLL_INTERVAL_MS);
  if (timer.unref) timer.unref();
  tick();

  const dispose = async () => {
    if (stopped) return;
    stopped = true;
    clearInterval(timer);
    for (const [sid, entry] of activeDeliveries) {
      if (entry.heartbeatTimer) clearInterval(entry.heartbeatTimer);
    }
    activeDeliveries.clear();
    clearQuestionDelivery();
    await post(DISPOSE_URL, { runtimeId }).catch(() => {});
  };
  if (api.lifecycle && typeof api.lifecycle.onDispose === 'function') api.lifecycle.onDispose(dispose);
  if (api.lifecycle && api.lifecycle.signal) api.lifecycle.signal.addEventListener('abort', dispose, { once: true });
}

export default { id: 'walker-tui-bridge', tui };
`;
}

module.exports = { getPluginSource };
